const body = $input.first().json.body || $input.first().json;
const eventType = body.type || 'unknown';
const data = body.data?.object || {};
const amount = (data.amount || data.amount_paid || data.amount_total || 0) / 100;
const currency = (data.currency || 'usd').toUpperCase();
const customer = data.customer_email || data.customer || 'unknown';
const creatorSplit = amount * 0.75;
const platformSplit = amount * 0.25;
return [{ json: { event: eventType, amount, currency, customer, creator_split: creatorSplit, platform_split: platformSplit, plowman_standard: '75/25', stripe_event_id: body.id, livemode: body.livemode, ts: new Date().toISOString() } }];
